195	// GetUserPortfolio returns the user's portfolio across markets.
196	func (s *Service) GetUserPortfolio(ctx context.Context, username string) (*Portfolio, error) {
197		bets, err := s.repo.ListUserBets(ctx, username)
198		if err != nil {
199			return nil, err
200		}
201	
202		marketMap := make(map[uint]*PortfolioItem)
203		for _, bet := range bets {
204			item, exists := marketMap[bet.MarketID]
205			if !exists {
206				item = &PortfolioItem{
207					MarketID:      bet.MarketID,
208					LastBetPlaced: bet.PlacedAt,
209				}
210				marketMap[bet.MarketID] = item
211			}
212			if bet.PlacedAt.After(item.LastBetPlaced) {
213				item.LastBetPlaced = bet.PlacedAt
214			}
215		}
216	
217		var items []PortfolioItem
218		var totalShares int64
219		for marketID, item := range marketMap {
220			position, err := s.repo.GetUserPositionInMarket(ctx, int64(marketID), username)
221			if err != nil {
222				return nil, err
223			}
224	
225			title, err := s.repo.GetMarketQuestion(ctx, marketID)
226			if err != nil {
227				return nil, err
228			}
229	
230			item.YesSharesOwned = position.YesSharesOwned
231			item.NoSharesOwned = position.NoSharesOwned
232			item.QuestionTitle = title
233			totalShares += position.YesSharesOwned + position.NoSharesOwned
234	
235			items = append(items, *item)
236		}
237	
238		sort.Slice(items, func(i, j int) bool {
239			return items[i].LastBetPlaced.After(items[j].LastBetPlaced)
240		})
241	
242		return &Portfolio{
243			Items:            items,
244			TotalSharesOwned: totalShares,
245		}, nil
246	}
