345	func (s *Service) sanitizePersonalLinks(links PersonalLinks) (PersonalLinks, error) {
346		if err := s.requireSanitizer(); err != nil {
347			return PersonalLinks{}, err
348		}
349	
350		values := links.Values()
351		for _, link := range values {
352			if len(link) > 200 {
353				return PersonalLinks{}, fmt.Errorf("personal link exceeds maximum length of 200 characters")
354			}
355		}
356	
357		sanitized := make([]string, len(values))
358		for i, link := range values {
359			if link == "" {
360				sanitized[i] = ""
361				continue
362			}
363			clean, err := s.sanitizer.SanitizePersonalLink(link)
364			if err != nil {
365				return PersonalLinks{}, fmt.Errorf("invalid personal link: %w", err)
366			}
367			sanitized[i] = clean
368		}
369		return PersonalLinks{
370			PersonalLink1: sanitized[0],
371			PersonalLink2: sanitized[1],
372			PersonalLink3: sanitized[2],
373			PersonalLink4: sanitized[3],
374		}, nil
375	}
