540	func ensurePasswordChanged(currentHash string, newPassword string) error {
541		if err := bcrypt.CompareHashAndPassword([]byte(currentHash), []byte(newPassword)); err == nil {
542			return fmt.Errorf("new password must differ from the current password")
543		}
544		return nil
545	}
546	
547	func hashPassword(password string) (string, error) {
548		hashed, err := bcrypt.GenerateFromPassword([]byte(password), passwordHashCost)
549		if err != nil {
550			return "", fmt.Errorf("failed to hash new password: %w", err)
551		}
552		return string(hashed), nil
553	}
