555	// ChangePassword validates credentials and persists a new hashed password.
556	func (s *Service) ChangePassword(ctx context.Context, username, currentPassword, newPassword string) error {
557		if err := s.validatePasswordChangeInputs(username, currentPassword, newPassword); err != nil {
558			return err
559		}
560	
561		creds, err := s.getCredentials(ctx, username)
562		if err != nil {
563			return err
564		}
565	
566		if err := s.verifyCurrentPassword(creds, currentPassword); err != nil {
567			return err
568		}
569	
570		sanitized, err := s.sanitizeNewPassword(newPassword)
571		if err != nil {
572			return err
573		}
574	
575		if err := ensurePasswordChanged(creds.PasswordHash, sanitized); err != nil {
576			return err
577		}
578	
579		hashed, err := hashPassword(sanitized)
580		if err != nil {
581			return err
582		}
583	
584		return s.repo.UpdatePassword(ctx, username, hashed, false)
585	}
